final:
module top_module(
    input [3:0] destReg,
    output reg [15:0] obf_decOut
    );always @ (destReg)
		begin
			obf_decOut = 0;
			case (destReg)
				4'h0 : obf_decOut = 16'h0001;
				4'h1 : obf_decOut = 16'h0002;
				4'h2 : obf_decOut = 16'h0004;
				4'h3 : obf_decOut = 16'h0008;
				4'h4 : obf_decOut = 16'h0010;
				4'h5 : obf_decOut = 16'h0020;
				4'h6 : obf_decOut = 16'h0040;
				4'h7 : obf_decOut = 16'h0080;
				4'h8 : obf_decOut = 16'h0100;
				4'h9 : obf_decOut = 16'h0200;
				4'hA : obf_decOut = 16'h0400;
				4'hB : obf_decOut = 16'h0800;
				4'hC : obf_decOut = 16'h1000;
				4'hD : obf_decOut = 16'h2000;
				4'hE : obf_decOut = 16'h4000;
				4'hF : obf_decOut = 16'h8000;
			endcase
		end

endmodule
